  'marketing.landing.routes.usefulFor': 'Útil para',
  'marketing.landing.routes.usefulForBody': 'Documentos, regalos, paquetes pequeños',
  'marketing.landing.routes.safetyNote': 'Seguridad',
  'marketing.landing.routes.safetyBody': 'Cumpla leyes, aduanas y guía de restringidos',
  'marketing.landing.routes.r1Origin': 'Estambul',
  'marketing.landing.routes.r1Dest': 'Nueva York',
